        .row-edit-btn {
            background: var(--accent-secondary);
            color: var(--accent-primary);
            padding: 4px;
            border-radius: 6px;
            display: flex;
            align-items: center;
            justify-content: center;
            opacity: 0.8;
            transition: all 0.2s;
        }
        .row-edit-btn:hover { opacity: 1; transform: translateY(-1px); }

        .mastery-pill { 
            font-size: 0.6rem; 
            padding: 3px 8px; 
            border-radius: 6px; 
            font-weight: 800; 
            text-transform: uppercase;
            letter-spacing: 0.5px;
        }
