            <div className="auth-header">
              <div className="header-info-group"><h3 style={{ fontSize: '1.4rem', fontWeight: 800 }}>Word Family</h3></div>
              <button onClick={() => setSelectedFamilyGroup(null)} className="close-button-cross"><svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
