        .mastery-pill { font-size: 0.6rem; padding: 3px 8px; border-radius: 6px; font-weight: 800; text-transform: uppercase; }
        .mastery-pill.new { background: var(--accent-secondary); color: var(--accent-primary); }
        .mastery-pill.learning { background: rgba(255, 193, 7, 0.1); color: #f57f17; }
        .mastery-pill.mastered { background: rgba(0, 200, 83, 0.1); color: #2e7d32; }

        .common-thread-box { background: var(--accent-secondary); border-radius: 16px; padding: 1rem; margin-bottom: 1.5rem; border: 1px solid var(--border-color); }
        .thread-label { font-size: 0.6rem; font-weight: 900; color: var(--accent-primary); letter-spacing: 1px; display: block; margin-bottom: 6px; }
        .modal-hint { font-size: 0.9rem; color: var(--text-primary); line-height: 1.5; font-weight: 600; margin: 0; }

        .family-member-card { padding: 1.15rem; background: var(--bg-color); border-radius: 20px; display: flex; flex-direction: column; gap: 6px; border: 1px solid var(--border-color); }
        .family-member-card.saved { background: var(--card-bg); border-color: var(--border-color); cursor: pointer; transition: transform 0.2s; }
        .family-member-card.saved:active { transform: scale(0.98); }
