        }
        .sparkle-icon-colorful {
            color: #FFD700;
            filter: drop-shadow(0 0 2px rgba(255, 215, 0, 0.3));
        }
        .header-explore-btn.active .sparkle-icon-colorful {
            color: #FFF;
        }
        .icon-btn:hover, .header-explore-btn:hover {
          background: var(--border-color);
