  };

  const renderUsageNotes = (notes: any) => {
    if (!notes) return null;
    const notesStr = typeof notes === 'string' ? notes : String(notes);
    const parts = notesStr.split(/(\[[A-Z-]+\]:?)/g).filter(Boolean);

    return (
      <div className="usage-box-container">
        {parts.map((part, idx) => {
          const isTag = /^\[[A-Z-]+\]:?$/.test(part);
          if (isTag) {
            const label = part.replace(/[\[\]:]/g, '');
            return <span key={idx} className={`usage-tag tag-${label.toLowerCase()}`}>{label}</span>;
          }
          return <p key={idx} className="usage-text-segment">{part.trim()}</p>;
        })}
      </div>
    );
  };

  if (topic === "__EMPTY_FALLBACK__") {
      return (
          <div className="flashcard-container" style={{ justifyContent: 'center', alignItems: 'center' }}>
              <div className="card-face card-front" style={{ position: 'relative', height: 'auto', minHeight: '350px', display: 'flex', flexDirection: 'column', padding: '2rem' }}>
                  <div style={{ fontSize: '3.5rem', marginBottom: '1.5rem' }}>📚</div>
                  <h2 style={{ textAlign: 'center', marginBottom: '1rem', fontWeight: 700 }}>Library is Empty</h2>
                  <p style={{ textAlign: 'center', color: 'var(--text-secondary)', padding: '0 1rem', lineHeight: '1.5', fontSize: '0.95rem' }}>
                      Start building your personalized library or try Explore mode.
                  </p>
                  <div style={{ display: 'flex', gap: '12px', marginTop: '2rem' }}>
                    <button className="primary-btn" onClick={onOpenImport}>Import Words</button>
                  </div>
              </div>
          </div>
      );
  }

  const isFavorite = favoriteWords.includes(topic);
  const srsItem = srsData[topic];

  const getStatusLabel = () => {
    if (isExploreMode) return `EXPLORING ${exploreProgress?.current}/${exploreProgress?.total}`;
    if (!srsItem || srsItem.reviewCount === 0) return 'NEW';
    if (srsItem.masteryLevel >= 5) return 'MASTERED';
    return 'LEARNING';
  };

  const statusLabel = getStatusLabel();

  const parseList = (val: any) => {
    if (!val || val === 'N/A') return [];
    if (Array.isArray(val)) return val.map(v => String(v).trim()).filter(Boolean);
    if (typeof val !== 'string') return [String(val)];
    return val.split(',').map(s => s.trim()).filter(Boolean);
  };

  const synonymsList = parseList(data.synonyms);
  const antonymsList = parseList(data.antonyms);
  const familyList = parseList(data.family);

  return (
    <div className="flashcard-container" onClick={() => setTooltip(null)}>
      <div className={`flashcard ${isFlipped ? 'flipped' : ''}`} onClick={(e) => {
          if ((e.target as HTMLElement).closest('.interactive-word-span') || (e.target as HTMLElement).closest('.fav-btn')) return;
          if (errorMsg) return;
          if (!isFlipped) setIsFlipped(true);
      }}>
        <div className="card-face card-front">
           <div className="card-actions-top">
               <button className={`icon-btn fav-btn ${isFavorite ? 'faved' : ''}`} onClick={(e) => { e.stopPropagation(); onToggleFavorite(topic); }}>
                 <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill={isFavorite ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2.5"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path></svg>
               </button>
           </div>
           <div className="word-display" style={{ fontSize: '2.5rem', fontWeight: 800 }}>{topic}</div>
           <div className="pos-tag" style={{ color: 'var(--md-sys-color-primary)', fontSize: '0.875rem', fontWeight: 600, letterSpacing: '1px' }}>{errorMsg ? 'ERROR' : (data.pos || '...').toUpperCase()}</div>

           {errorMsg ? (
               <p style={{ textAlign: 'center', color: 'var(--text-secondary)', padding: '1rem' }}>{errorMsg}</p>
           ) : (
               <>
                <div className="status-badge" style={{ marginTop: '16px', background: 'var(--md-sys-color-secondary-container)', color: 'var(--md-sys-color-on-secondary-container)', padding: '6px 16px', borderRadius: '16px', fontSize: '0.75rem', fontWeight: 700 }}>{statusLabel}</div>
                <div className="tap-hint" style={{ marginTop: 'auto', marginBottom: '24px', opacity: 0.6, fontSize: '0.75rem', fontWeight: 600 }}>{isLoading ? 'Fetching...' : 'Tap to reveal'}</div>
               </>
           )}
        </div>

        <div className="card-face card-back">
           <div className="card-back-header" style={{ padding: '16px 24px' }}>
             <h2 style={{ fontSize: '1.25rem', fontWeight: 700, margin: 0 }}>{topic}</h2>
             <button className={`icon-btn fav-btn ${isFavorite ? 'faved' : ''}`} onClick={(e) => { e.stopPropagation(); onToggleFavorite(topic); }}>
                <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill={isFavorite ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2.5"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path></svg>
             </button>
           </div>

           <div className="card-back-scrollable" style={{ padding: '0 24px 24px' }}>
                {visibilitySettings.definition && (
                    <div style={{ marginBottom: '16px' }}>
                        <div className="section-label" style={{ fontSize: '0.65rem', fontWeight: 700, opacity: 0.7, marginBottom: '4px' }}>DEFINITION</div>
                        <div className="def-text" style={{ fontSize: '1.05rem', lineHeight: 1.5 }}>
                            <InteractiveText text={String(data.definition || '...')} onWordClick={handleWordClick} />
