                    </div>
                )}

                {visibilitySettings.bengali && data.bengali && (
                    <div style={{ marginBottom: '16px' }}>
                        <div className="section-label" style={{ fontSize: '0.65rem', fontWeight: 700, opacity: 0.7, marginBottom: '4px' }}>BENGALI</div>
