import { GoogleGenAI } from '@google/genai';
import { DICTIONARY_WORDS, VOCAB_LEVELS } from './dictionaryData';

export interface CardData {
  pos: string;
  ipa?: string;
  definition: string;
  bengali: string;
  family: string;
  context: string;
  synonyms: string;
  antonyms: string;
  difficulty: string;
  etymology?: string;
  usage_notes?: string;
  source?: string;
  word?: string;
}

export type VocabLevel = 'basic' | 'intermediate' | 'gre' | 'ielts' | 'expert';

let aiInstance: GoogleGenAI | null = null;

const getAIClient = () => {
  if (!aiInstance) {
    aiInstance = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiInstance;
};

export const capitalize = (s: string) => s ? s.charAt(0).toUpperCase() + s.slice(1).toLowerCase() : s;

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json/g, '').replace(/```/g, '').trim();
};

export async function searchVocabulary(query: string): Promise<string[]> {
  const cleanQuery = query.trim();
  if (cleanQuery.length < 2) return [];
  if (!navigator.onLine) {
    return DICTIONARY_WORDS.filter(w => w.toLowerCase().startsWith(cleanQuery.toLowerCase())).slice(0, 8).map(capitalize);
  }
  try {
    const response = await fetch(`https://api.datamuse.com/sug?s=${encodeURIComponent(cleanQuery)}&max=8`);
    const data = await response.json();
    return data.map((item: any) => capitalize(item.word));
  } catch (error) {
    return DICTIONARY_WORDS.filter(w => w.toLowerCase().startsWith(cleanQuery.toLowerCase())).slice(0, 8).map(capitalize);
  }
}

export async function fetchWordData(word: string, definitionStyle: string = 'standard', retries = 1): Promise<CardData> {
  const normalizedWord = capitalize(word);
  const isLocalWord = DICTIONARY_WORDS.some(w => w.toLowerCase() === word.toLowerCase());
  const localFallback: CardData = {
    pos: isLocalWord ? 'common word' : 'word',
    definition: `AI details for "${normalizedWord}" are pending.`,
    bengali: 'অফলাইন থাকার কারণে বিস্তারিত পাওয়া যায়নি',
    family: 'N/A',
    context: `The word "${normalizedWord}" is saved in your library.`,
    synonyms: 'N/A',
    antonyms: 'N/A',
    difficulty: 'Standard',
    source: 'Local Cache',
    word: normalizedWord
  };

  if (!navigator.onLine) return localFallback;

  const ai = getAIClient();
  const styleInstruction = definitionStyle === 'concise' 
    ? 'Keep the definition under 12 words.' 
    : (definitionStyle === 'detailed' ? 'Provide a nuanced definition (30-40 words).' : 'Provide a clear, standard definition.');

  const prompt = `Define "${normalizedWord}" for a vocabulary card.
  ${styleInstruction}
  Return JSON with: "pos", "definition", "bengali", "family", "context", "synonyms", "antonyms", "difficulty", "etymology", "usage_notes".
  RULES:
  1. "family": Include forms WITH POS, e.g., "happily (adv), happiness (n)".
  2. "usage_notes": Use [TRAP], [MNEMONIC], [VIBE], [TIP] tags.
  Format: Raw JSON only.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { responseMimeType: "application/json", thinkingConfig: { thinkingBudget: 0 } }
    });
    const data = JSON.parse(cleanJsonResponse(response.text || '{}'));
    if (data.bengali) data.bengali = data.bengali.replace(/\s*\([^)]*[a-zA-Z][^)]*\)/g, '').trim();
    return { ...data, word: normalizedWord, source: 'Gemini AI' };
  } catch (error) {
    if (retries > 0) return fetchWordData(normalizedWord, definitionStyle, retries - 1);
    return localFallback;
  }
}

export async function fetchExplorePack(level: VocabLevel = 'intermediate', count: number = 10, excludeWords: string[] = []): Promise<CardData[]> {
  if (!navigator.onLine) throw new Error("Offline");
  const ai = getAIClient();
  const excludeInstruction = excludeWords.length > 0 
    ? `MANDATORY: DO NOT INCLUDE: ${excludeWords.slice(-200).join(', ')}.` 
    : '';

  const prompt = `Generate ${count} unique ${level} level vocabulary words.
  ${excludeInstruction}
  MANDATORY: Return a JSON array of objects with keys: "word", "pos", "definition", "bengali", "family", "context", "synonyms", "antonyms", "difficulty", "etymology", "usage_notes".
  "family" MUST include POS in brackets.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { responseMimeType: "application/json", thinkingConfig: { thinkingBudget: 0 } }
    });
    const data = JSON.parse(cleanJsonResponse(response.text || '[]'));
    return data.map((item: any) => ({ 
      ...item, 
      word: capitalize(item.word || ''), 
      bengali: item.bengali?.replace(/\s*\([^)]*[a-zA-Z][^)]*\)/g, '').trim(), 
      source: 'Gemini Explore' 
    }));
  } catch (error) {
    console.error("Explore failed", error);
    return [];
  }
}

export async function generateBulkWordData(words: string[]): Promise<Record<string, CardData>> {
  if (!navigator.onLine) throw new Error("Offline");
  const ai = getAIClient();
  const prompt = `Generate cards for: ${words.join(', ')}. Return JSON array of objects with keys: "word", "pos", "definition", "bengali", "family", "context", "synonyms", "antonyms", "difficulty", "etymology", "usage_notes".`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { responseMimeType: "application/json", thinkingConfig: { thinkingBudget: 0 } }
    });
    const results = JSON.parse(cleanJsonResponse(response.text || '[]'));
    const finalCache: Record<string, CardData> = {};
    results.forEach((item: any) => {
      if (item.word) {
        const w = capitalize(item.word);
        finalCache[w] = { ...item, word: w, source: 'Gemini Bulk' };
      }
    });
    return finalCache;
  } catch (error) {
    throw error;
  }
}

export async function fetchContextSentence(word: string): Promise<string> {
  const ai = getAIClient();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate one concise example sentence for "${word}". No intro.`,
    });
    return response.text.trim();
  } catch (error) {
    return `Could not generate sentence for "${word}".`;
  }
}

export async function generateSemanticClusters(words: string[], level: number = 2): Promise<any[]> {
    if (!navigator.onLine) return [];
    const ai = getAIClient();
    const prompt = `Organize these words into groups: ${words.join(', ')}. Similarity level ${level} (0=strict, 2=thematic). Return JSON array of objects with "title", "members" (array), "explanation".`;
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: "application/json", thinkingConfig: { thinkingBudget: 0 } }
        });
        const data = JSON.parse(cleanJsonResponse(response.text || '[]'));
        return data.map((item: any, idx: number) => ({ ...item, id: `cluster-${Date.now()}-${idx}`, level }));
    } catch (e) {
        return [];
    }
}

export async function getShortDefinition(word: string): Promise<string> {
  try {
    const data = await fetchWordData(word);
    return `(${data.pos}) ${data.definition}\n${data.bengali}`;
  } catch (e) {
    return "Definition unavailable.";
  }
}

