  const [activeTab, setActiveTab] = useState<Tab>('home');
  const [currentTopic, setCurrentTopic] = useState<string>('');
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [isSyncing, setIsSyncing] = useState(false);

  const [savedWords, setSavedWords] = useState<string[]>(() => JSON.parse(localStorage.getItem('savedWords') || '[]'));
  const [favoriteWords, setFavoriteWords] = useState<string[]>(() => JSON.parse(localStorage.getItem('favoriteWords') || '[]'));
  const [trashedWords, setTrashedWords] = useState<string[]>(() => JSON.parse(localStorage.getItem('trashedWords') || '[]'));
  const [srsData, setSrsData] = useState<Record<string, SRSItem>>(() => JSON.parse(localStorage.getItem('srsData') || '{}'));
  const [cardCache, setCardCache] = useState<Record<string, CardData>>(() => JSON.parse(localStorage.getItem('cardCache') || '{}'));

  const [semanticClusters, setSemanticClusters] = useState<SemanticCluster[]>(() => JSON.parse(localStorage.getItem('semanticClusters') || '[]'));
  const [clusterSimilarity, setClusterSimilarity] = useState<number>(() => Number(localStorage.getItem('clusterSimilarity')) || 1);

  const [visibilitySettings, setVisibilitySettings] = useState<VisibilitySettings>(() => {
    const saved = localStorage.getItem('visibilitySettings');
    return saved ? JSON.parse(saved) : DEFAULT_VISIBILITY;
  });
  const [explorePackSize, setExplorePackSize] = useState<number>(() => Number(localStorage.getItem('explorePackSize')) || 10);
  const [definitionStyle, setDefinitionStyle] = useState<string>(() => localStorage.getItem('definitionStyle') || 'standard');

  const [isBulkImportOpen, setIsBulkImportOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isTrashOpen, setIsTrashOpen] = useState(false);
  const [user, setUser] = useState<any>(null);
  const [shouldStartFlipped, setShouldStartFlipped] = useState(false);

  const [isExploreMode, setIsExploreMode] = useState(false);
  const [explorePack, setExplorePack] = useState<string[]>([]);
  const [exploreIndex, setExploreIndex] = useState(-1);
  const [isExploring, setIsExploring] = useState(false);

  const syncQueue = useRef<string[]>([]);
  const isSyncProcessing = useRef(false);

  const processSyncQueue = async () => {
    if (isSyncProcessing.current || !isOnline || syncQueue.current.length === 0) return;
    isSyncProcessing.current = true;
    setIsSyncing(true);
    while (syncQueue.current.length > 0 && isOnline) {
      const word = syncQueue.current.shift();
      const capitalizedWord = word ? capitalize(word) : null;
      if (capitalizedWord && !cardCache[capitalizedWord]) {
        try {
          const data = await fetchWordData(capitalizedWord, definitionStyle);
          handleCacheUpdate(capitalizedWord, data);
          await new Promise(resolve => setTimeout(resolve, 2000));
        } catch (e) {
          console.warn(`Sync failed for ${capitalizedWord}`);
        }
      }
    }
    isSyncProcessing.current = false;
    setIsSyncing(false);
  };

  useEffect(() => {
    const missing = savedWords.filter(w => !cardCache[w]);
    if (missing.length > 0 && isOnline) {
      syncQueue.current = [...new Set([...syncQueue.current, ...missing])];
      processSyncQueue();
    }
  }, [savedWords, isOnline, cardCache]);

  const loadDataFromSupabase = useCallback(async (userId: string) => {
    if (!navigator.onLine) return;
    const cloudData = await getUserData(userId);
    if (cloudData) {
        setSavedWords((cloudData.savedWords || []).map(capitalize));
        setFavoriteWords((cloudData.favoriteWords || []).map(capitalize));
        setTrashedWords((cloudData.trashedWords || []).map(capitalize));
        setSemanticClusters(cloudData.semanticClusters || []);
        if (cloudData.clusterSimilarity !== undefined) setClusterSimilarity(cloudData.clusterSimilarity);

        const srs: Record<string, SRSItem> = {};
        Object.entries(cloudData.srsData || {}).forEach(([k, v]) => { srs[capitalize(k)] = v as SRSItem; });
        setSrsData(srs);

        const cache: Record<string, CardData> = {};
        Object.entries(cloudData.cardCache || {}).forEach(([k, v]) => { cache[capitalize(k)] = v as CardData; });
        setCardCache(prev => ({ ...prev, ...cache }));
    }
  }, []);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    document.body.setAttribute('data-theme', theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    if (!currentTopic) handleRandom();
  }, []);

  useEffect(() => {
    localStorage.setItem('savedWords', JSON.stringify(savedWords));
    localStorage.setItem('favoriteWords', JSON.stringify(favoriteWords));
    localStorage.setItem('trashedWords', JSON.stringify(trashedWords));
    localStorage.setItem('srsData', JSON.stringify(srsData));
    localStorage.setItem('cardCache', JSON.stringify(cardCache));
    localStorage.setItem('visibilitySettings', JSON.stringify(visibilitySettings));
    localStorage.setItem('explorePackSize', String(explorePackSize));
    localStorage.setItem('definitionStyle', definitionStyle);
    localStorage.setItem('semanticClusters', JSON.stringify(semanticClusters));
    localStorage.setItem('clusterSimilarity', String(clusterSimilarity));

    if (user && isOnline) saveUserData(user.id, { savedWords, favoriteWords, trashedWords, srsData, cardCache, semanticClusters, clusterSimilarity });
  }, [savedWords, favoriteWords, trashedWords, srsData, cardCache, user, isOnline, visibilitySettings, explorePackSize, definitionStyle, semanticClusters, clusterSimilarity]);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      const activeUser = session?.user ?? null;
      setUser(activeUser);
      if (activeUser && isOnline) loadDataFromSupabase(activeUser.id);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
      const activeUser = session?.user ?? null;
      setUser(activeUser);
      if (activeUser && isOnline) loadDataFromSupabase(activeUser.id);
    });
    return () => subscription.unsubscribe();
  }, [isOnline, loadDataFromSupabase]);

  const handleRandom = () => {
      if (isExploreMode && explorePack.length > 0) {
          const nextIdx = exploreIndex + 1;
          if (nextIdx < explorePack.length) {
              setExploreIndex(nextIdx);
              setShouldStartFlipped(false);
              setCurrentTopic(capitalize(explorePack[nextIdx]));
          } else {
              handleToggleExplore(true);
          }
          return;
      }
      if (savedWords.length > 0) {
          const dueCached = getDueWords(savedWords, srsData);
          const nextWord = dueCached[0] || savedWords[Math.floor(Math.random() * savedWords.length)];
          setShouldStartFlipped(false);
          setCurrentTopic(capitalize(nextWord));
      } else {
          setCurrentTopic("__EMPTY_FALLBACK__");
      }
  };

  const handleNavigate = (word: string, initialFlipped: boolean = false) => {
      if (word === '__RANDOM__') {
          handleRandom();
      } else if (word === '__PREV__') {
          if (isExploreMode && exploreIndex > 0) {
            const prevIdx = exploreIndex - 1;
            setExploreIndex(prevIdx);
            setShouldStartFlipped(true);
            setCurrentTopic(capitalize(explorePack[prevIdx]));
          }
      } else if (word === '__GENERATE__') {
          handleToggleExplore(true);
      } else {
          setShouldStartFlipped(initialFlipped);
          setCurrentTopic(capitalize(word));
      }
      setActiveTab('home');
  };

  const handleToggleSave = (word: string) => {
      const capitalizedWord = capitalize(word);
      const exists = savedWords.some(w => w.toLowerCase() === capitalizedWord.toLowerCase());
      if (exists) {
          handleMoveToTrash([capitalizedWord]);
      } else {
          setSavedWords(prev => [capitalizedWord, ...prev]);
          if (!srsData[capitalizedWord]) setSrsData(prev => ({ ...prev, [capitalizedWord]: initializeSRSItem(capitalizedWord) }));
      }
  };

  const handleCacheUpdate = (word: string, data: CardData) => {
    const capWord = capitalize(word);
    setCardCache(prev => ({ ...prev, [capWord]: { ...data, word: capWord } }));
    if (capWord !== "__EMPTY_FALLBACK__" && !savedWords.includes(capWord)) {
      setSavedWords(prev => [capWord, ...prev]);
      if (!srsData[capWord]) setSrsData(prev => ({ ...prev, [capWord]: initializeSRSItem(capWord) }));
    }
  };

  const handleToggleExplore = async (forceNext: boolean = false) => {
    if (isExploreMode && !forceNext) {
      setIsExploreMode(false);
      setExplorePack([]);
      setExploreIndex(-1);
      handleRandom();
    } else {
      if (!isOnline) return;
      setIsExploring(true);
      try {
        const wordsToExclude = [...savedWords, ...explorePack, ...trashedWords];
        const pack = await fetchExplorePack('intermediate', explorePackSize, wordsToExclude);
        if (pack.length > 0) {
          const newPackWords = pack.map(p => capitalize(p.word!));
          const newCache = { ...cardCache };
          pack.forEach(p => { if(p.word) newCache[capitalize(p.word)] = { ...p, word: capitalize(p.word) }; });
          setCardCache(newCache);
          setExplorePack(newPackWords);
          setExploreIndex(0);
          setIsExploreMode(true);
          setCurrentTopic(newPackWords[0]);
          setShouldStartFlipped(false);
        }
      } catch (e) {
        console.error(e);
      } finally {
        setIsExploring(false);
      }
    }
  };

  const handleImportWords = (importedCache: Record<string, CardData>) => {
      const sanitizedCache: Record<string, CardData> = {};
      const newWords: string[] = [];
      Object.entries(importedCache).forEach(([word, data]) => {
          const capWord = capitalize(word);
          sanitizedCache[capWord] = { ...data, word: capWord };
          if (!savedWords.includes(capWord)) newWords.push(capWord);
      });
      setCardCache(prev => ({ ...prev, ...sanitizedCache }));
      if (newWords.length > 0) {
          setSavedWords(prev => [...newWords, ...prev]);
          setSrsData(prev => {
              const next = { ...prev };
              newWords.forEach(w => { if (!next[w]) next[w] = initializeSRSItem(w); });
              return next;
          });
      }
  };

  const handleUpdateWordData = (oldWord: string, newWord: string, newData: CardData) => {
    const capOld = capitalize(oldWord);
    const capNew = capitalize(newWord);
    setCardCache(prev => {
      const next = { ...prev, [capNew]: { ...newData, word: capNew } };
      if (capOld !== capNew) delete next[capOld];
      return next;
    });
    setSavedWords(prev => prev.map(w => w === capOld ? capNew : w));
    if (currentTopic === capOld) setCurrentTopic(capNew);
  };

  const handleMoveToTrash = (words: string[]) => {
      const capWords = words.map(capitalize);
      setSavedWords(prev => prev.filter(w => !capWords.includes(w)));
      setFavoriteWords(prev => prev.filter(w => !capWords.includes(w)));
      setTrashedWords(prev => [...new Set([...capWords, ...prev])]);
      if (capWords.includes(currentTopic)) handleRandom();
  };

  const handleRestoreFromTrash = (words: string[]) => {
      const capWords = words.map(capitalize);
      setTrashedWords(prev => prev.filter(w => !capWords.includes(w)));
      setSavedWords(prev => [...new Set([...capWords, ...prev])]);
  };

  const handlePermanentDelete = (words: string[]) => {
      const capWords = words.map(capitalize);
      setTrashedWords(prev => prev.filter(w => !capWords.includes(w)));
  };

  const handleToggleFavorite = (word: string) => {
      const capWord = capitalize(word);
      if (favoriteWords.includes(capWord)) {
          setFavoriteWords(prev => prev.filter(w => w !== capWord));
      } else {
          setFavoriteWords(prev => [capWord, ...prev]);
      }
  };

  const handleSRSUpdate = (word: string, grade: 'know' | 'dont_know') => {
      const capWord = capitalize(word);
      const currentItem = srsData[capWord] || initializeSRSItem(capWord);
      setSrsData(prev => ({ ...prev, [capWord]: calculateSRS(currentItem, grade) }));
      handleRandom();
  };

  const handleResetSRS = () => {
    setSrsData(prev => {
      const next: Record<string, SRSItem> = {};
      Object.keys(prev).forEach(w => { next[w] = initializeSRSItem(w); });
      return next;
    });
  };

  const cachedCount = savedWords.filter(w => cardCache[w]).length;

  return (
    <div className="app-container" style={{ height: '100dvh', display: 'flex', flexDirection: 'column' }}>
      <header className="app-header">
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <div className="logo-text">LexiFlow</div>
          {(isSyncing || isExploring) && <div className="sync-spinner" />}
        </div>
        <div className="header-actions">
            {!isOnline && <span className="chip" style={{ background: 'var(--md-sys-color-error)', color: 'white', border: 'none' }}>OFFLINE</span>}

            {activeTab === 'home' && (
              <>
               <button 
                className={`tonal-btn ${isExploreMode ? 'active' : ''}`} 
                onClick={() => handleToggleExplore()}
                style={{ 
                    marginRight: '8px',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px',
                    padding: '8px 16px',
                    background: isExploreMode ? 'var(--md-sys-color-primary)' : 'var(--md-sys-color-secondary-container)',
                    color: isExploreMode ? 'var(--md-sys-color-on-primary)' : 'var(--md-sys-color-on-secondary-container)'
                }}
               >
                 <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
                 <span>Explore</span>
               </button>
               <button className="icon-btn" onClick={() => setIsBulkImportOpen(true)} title="Import">
                   <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path><polyline points="17 8 12 3 7 8"></polyline><line x1="12" y1="3" x2="12" y2="15"></line></svg>
                </button>
              </>
            )}

            {activeTab === 'saved' && (
              <div style={{ display: 'flex', gap: '8px' }}>
                <button className="icon-btn" onClick={() => setIsTrashOpen(true)} title="Trash">
                   <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                </button>
                <button className="icon-btn" onClick={() => setIsBulkImportOpen(true)} title="Import">
                   <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path><polyline points="17 8 12 3 7 8"></polyline><line x1="12" y1="3" x2="12" y2="15"></line></svg>
                </button>
              </div>
            )}

            <button className="icon-btn" onClick={() => setIsSettingsOpen(true)} style={{ marginLeft: '4px' }}>
                <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="4" y1="21" x2="4" y2="14"></line><line x1="4" y1="10" x2="4" y2="3"></line><line x1="12" y1="21" x2="12" y2="12"></line><line x1="12" y1="8" x2="12" y2="3"></line><line x1="20" y1="21" x2="20" y2="16"></line><line x1="20" y1="12" x2="20" y2="3"></line><line x1="1" y1="14" x2="7" y2="14"></line><line x1="9" y1="8" x2="15" y2="8"></line><line x1="17" y1="16" x2="23" y2="16"></line></svg>
            </button>
        </div>
      </header>

      <main style={{ flex: 1, overflow: 'hidden', padding: '16px' }}>
        {activeTab === 'home' && <FlashcardView topic={currentTopic} savedWords={savedWords} favoriteWords={favoriteWords} srsData={srsData} cardCache={cardCache} onUpdateSRS={handleSRSUpdate} onToggleSave={handleToggleSave} onToggleFavorite={handleToggleFavorite} onNavigate={handleNavigate} onCacheUpdate={handleCacheUpdate} onOpenImport={() => setIsBulkImportOpen(true)} isOnline={isOnline} visibilitySettings={visibilitySettings} isExploreMode={isExploreMode} exploreProgress={isExploreMode ? { current: exploreIndex + 1, total: explorePack.length } : undefined} />}
        {activeTab === 'saved' && <SavedWordsList savedWords={savedWords} favoriteWords={favoriteWords} trashedWords={trashedWords} srsData={srsData} cardCache={cardCache} onNavigate={handleNavigate} onDeleteMultiple={handleMoveToTrash} onRestoreFromTrash={handleRestoreFromTrash} onPermanentDelete={handlePermanentDelete} onOpenImport={() => setIsBulkImportOpen(true)} onUpdateWordData={handleUpdateWordData} semanticClusters={semanticClusters} setSemanticClusters={setSemanticClusters} clusterSimilarity={clusterSimilarity} setClusterSimilarity={setClusterSimilarity} isOnline={isOnline} />}
        {activeTab === 'profile' && <ProfileView user={user} savedCount={savedWords.length} cachedCount={cachedCount} srsData={srsData} onSignOut={() => supabase.auth.signOut()} onLogin={() => {}} isOnline={isOnline} onResetSRS={handleResetSRS} />}
      </main>

      <div className="bottom-nav-container">
        <nav className="bottom-nav">
            <button className={`nav-item ${activeTab === 'home' ? 'active' : ''}`} onClick={() => setActiveTab('home')}>
                <div className="icon-wrapper"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path><polyline points="9 22 9 12 15 12 15 22"></polyline></svg></div>
                <span>Study</span>
            </button>
            <button className={`nav-item ${activeTab === 'saved' ? 'active' : ''}`} onClick={() => setActiveTab('saved')}>
                <div className="icon-wrapper"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"></path></svg></div>
                <span>Library</span>
            </button>
            <button className={`nav-item ${activeTab === 'profile' ? 'active' : ''}`} onClick={() => setActiveTab('profile')}>
                <div className="icon-wrapper"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path><circle cx="12" cy="7" r="4"></circle></svg></div>
                <span>Profile</span>
            </button>
        </nav>
      </div>

      {isBulkImportOpen && <BulkImportModal onClose={() => setIsBulkImportOpen(false)} onImport={handleImportWords} />}
      {isSettingsOpen && <CardSettingsModal visibility={visibilitySettings} onUpdateVisibility={setVisibilitySettings} explorePackSize={explorePackSize} onUpdatePackSize={setExplorePackSize} definitionStyle={definitionStyle} onUpdateDefinitionStyle={setDefinitionStyle} onClose={() => setIsSettingsOpen(false)} />}
      {isTrashOpen && <TrashModal trashedWords={trashedWords} cardCache={cardCache} onClose={() => setIsTrashOpen(false)} onRestore={handleRestoreFromTrash} onPermanentDelete={handlePermanentDelete} />}

      <style>{`
        .sync-spinner {
          width: 14px; height: 14px;
          border: 2.5px solid var(--md-sys-color-surface-variant);
          border-top-color: var(--md-sys-color-primary);
          border-radius: 50%;
          animation: spin 0.8s linear infinite;
        }
        @keyframes spin { to { transform: rotate(360deg); } }
        .bottom-nav-container { padding-bottom: env(safe-area-inset-bottom); }
      `}</style>
    </div>
  );
};

export default App;

