          }
          .action-btn-back {
              padding: 8px 14px;
              border-radius: 10px;
              font-weight: 700;
              font-size: 0.75rem;
              background: var(--accent-secondary);
              color: var(--accent-primary);
              border: 1px solid var(--border-color);
          }
          .action-btn-back:active { transform: scale(0.95); }

          .nav-icon-btn {
            width: 56px;
            height: 56px;
            border-radius: 50%;
            background: var(--card-bg);
            border: 1px solid var(--border-color);
            color: var(--text-primary);
            display: flex;
            align-items: center;
