              100% { box-shadow: 0 0 0 0 rgba(88, 86, 214, 0); }
          }

          .status-badge.explore-badge {
            background: linear-gradient(135deg, #5856d6 0%, #ff2d55 100%);
            color: white;
            border: none;
          }

          .usage-box-container {
              display: flex;
              flex-direction: column;
              gap: 8px;
          }
          .usage-tag {
              display: inline-block;
              font-size: 0.65rem;
