          }
          .tag-trap { background: #fee2e2; color: #991b1b; }
          .tag-mnemonic { background: #fef9c3; color: #854d0e; }
          .tag-vibe { background: #e0e7ff; color: #3730a3; }
          .tag-context { background: #dcfce7; color: #166534; }
