          .card-actions-top {
            position: absolute;
            top: 1.5rem;
            right: 1.5rem;
            display: flex;
            flex-direction: column;
            gap: 12px;
            z-index: 10;
          }
          .fav-btn { 
            color: var(--text-muted); 
            transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1); 
          }
          .fav-btn.faved { 
            color: #ff2d55; 
            fill: #ff2d55;
            transform: scale(1.1);
          }
