// Fix: Define WordSource locally as it is not exported from App.tsx
export type WordSource = 'ai' | 'free' | 'local';

let ai: GoogleGenAI;
// Fixed: Using process.env.API_KEY directly as per SDK guidelines
const getAiClient = () => {
  if (!ai) {
    ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return ai;
};

const textModelName = 'gemini-3-flash-preview';

export interface CardData {
  pos: string;
  // Added optional ipa property for phonetic transcription support
  ipa?: string;
  definition: string;
  bengali: string;
  family: string;
  context: string;
  synonyms: string;
  antonyms: string;
  difficulty: string;
  // Removed etymology property
