/**
 * Enhanced Explore logic:
 * 1. Fetch a pool of words from Datamuse (External API) based on level-appropriate topics.
 * 2. Filter out already saved/trashed/seen words locally.
 * 3. Send the confirmed "new" words to Gemini for high-quality card generation.
 */
export async function fetchExplorePack(level: VocabLevel = 'intermediate', count: number = 10, excludeWords: string[] = []): Promise<CardData[]> {
  if (!navigator.onLine) throw new Error("Offline");

  const excludeSet = new Set(excludeWords.map(w => w.toLowerCase()));
  const topics = {
    basic: ['nature', 'family', 'house'],
    intermediate: ['business', 'travel', 'emotion'],
    gre: ['philosophy', 'logic', 'art', 'rhetoric'],
    ielts: ['academic', 'environment', 'society'],
    expert: ['literature', 'science', 'theory', 'abstract']
  };

  const currentTopics = topics[level] || topics.intermediate;
  const randomTopic = currentTopics[Math.floor(Math.random() * currentTopics.length)];

  try {
    // Phase 1: Get a large word pool from Datamuse
    const datamuseRes = await fetch(`https://api.datamuse.com/words?topics=${randomTopic}&max=100`);
    const pool = await datamuseRes.json();

    // Phase 2: Local Filtering
    const candidateWords = pool
      .map((item: any) => item.word)
      .filter((word: string) => 
        word.length > 3 && 
        !word.includes(' ') && 
        !excludeSet.has(word.toLowerCase())
      )
      .slice(0, count);

    if (candidateWords.length === 0) {
      // Fallback if filter is too strict: generate purely via AI but keep it smart
      return await generatePureAiPack(level, count, excludeWords);
    }

    // Phase 3: AI enrichment for specific unique words
    return await generateBulkCardData(candidateWords);
  } catch (e) {
    console.warn("Datamuse fetch failed, falling back to pure AI explore", e);
    return await generatePureAiPack(level, count, excludeWords);
  }
}

async function generatePureAiPack(level: string, count: number, excludeWords: string[]): Promise<CardData[]> {
  const ai = getAIClient();
  const prompt = `Generate ${count} high-level ${level} vocabulary words. DO NOT include any of these: ${excludeWords.slice(-50).join(', ')}.`;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: { type: Type.ARRAY, items: { ...cardSchema, properties: { ...cardSchema.properties, word: { type: Type.STRING } }, required: [...cardSchema.required, "word"] } }
    }
  });
  return safeJsonParse(response.text, []);
}

export async function generateBulkCardData(words: string[]): Promise<CardData[]> {
  const ai = getAIClient();
  const prompt = `You are a professional dictionary editor. Create high-quality vocabulary cards for: ${words.join(', ')}. 
  Provide scholarly definitions, nuanced examples, and accurate Bengali meanings.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: { 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          ...cardSchema,
          properties: { ...cardSchema.properties, word: { type: Type.STRING } },
          required: [...cardSchema.required, "word"]
        }
      }
    }
  });

  const results = safeJsonParse(response.text, []);
  return results.map((item: any) => ({
    ...item,
    word: capitalize(item.word),
    source: 'Gemini AI'
  }));
}

export async function generateBulkWordData(words: string[]): Promise<Record<string, CardData>> {
  const cards = await generateBulkCardData(words);
  const cache: Record<string, CardData> = {};
  cards.forEach(card => {
    if (card.word) cache[card.word] = card;
  });
  return cache;
}

export async function generateSemanticClusters(words: string[], level: number = 2): Promise<SemanticCluster[]> {
    if (!navigator.onLine || words.length === 0) return [];
    const ai = getAIClient();
    const prompt = `Group these words by similarity (level ${level}/2): ${words.join(', ')}.`;
    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { 
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { title: { type: Type.STRING }, members: { type: Type.ARRAY, items: { type: Type.STRING } }, explanation: { type: Type.STRING } }, required: ["title", "members", "explanation"] } }
        }
    });
    const data = safeJsonParse(response.text, []);
    return data.map((item: any, idx: number) => ({ ...item, id: `cluster-${idx}-${Date.now()}`, isAiGenerated: true }));
}

export async function fetchContextSentence(word: string): Promise<string> {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Write one scholarly example sentence for "${word}":`
  });
  return response.text?.trim() || `Example using ${word}.`;
}

export async function getShortDefinition(word: string): Promise<string> {
  try {
    const data = await fetchWordData(word);
    return `(${data.pos}) ${data.definition}\n${data.bengali}`;
  } catch (e) {
    return "Definition unavailable.";
  }
}

