import React, { useState, useEffect, useRef } from 'react';
import { fetchWordData, CardData, getShortDefinition, capitalize } from '../services/dictionaryService';
import { Grade, SRSItem } from '../services/srsService';
import InteractiveText from './InteractiveText';
import WordTooltip from './WordTooltip';
import type { VisibilitySettings } from '../App';

interface FlashcardViewProps {
  topic: string;
  initialFlipped?: boolean;
  savedWords: string[];
  favoriteWords: string[];
  srsData: Record<string, SRSItem>;
  cardCache: Record<string, CardData>;
  onUpdateSRS: (word: string, grade: Grade) => void;
  onToggleSave: (word: string) => void;
  onToggleFavorite: (word: string) => void;
  onNavigate: (word: string, initialFlipped?: boolean) => void;
  onCacheUpdate: (word: string, data: CardData) => void;
  onOpenImport: () => void;
  isOnline: boolean;
  visibilitySettings: VisibilitySettings;
  isExploreMode?: boolean;
  exploreProgress?: { current: number, total: number };
}

const FlashcardView: React.FC<FlashcardViewProps> = ({ 
    topic, initialFlipped = false, savedWords, favoriteWords, srsData, cardCache, onUpdateSRS, onToggleSave, onToggleFavorite, onNavigate, onCacheUpdate, onOpenImport, isOnline, visibilitySettings,
    isExploreMode = false, exploreProgress
}) => {
  const [isFlipped, setIsFlipped] = useState(initialFlipped);
  const [data, setData] = useState<CardData>({ pos: '...', definition: '', bengali: '', family: '', context: '', synonyms: '', antonyms: '', difficulty: '' });
  const [isLoading, setIsLoading] = useState(false);
  const [isRegenerating, setIsRegenerating] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const activeTopic = useRef(topic);
  const [tooltip, setTooltip] = useState<any>(null);

  useEffect(() => {
    if (topic && topic !== "__EMPTY_FALLBACK__") {
        loadTopic(topic);
        setIsFlipped(initialFlipped);
    }
  }, [topic, initialFlipped]);

  const loadTopic = async (word: string) => {
    activeTopic.current = word;
    setErrorMsg(null);
    if (cardCache[word]) {
        setData(cardCache[word]);
        return;
    }
    if (!isOnline) {
      setErrorMsg("Offline: Word not cached.");
      return;
    }
    setIsLoading(true);
    try {
      const result = await fetchWordData(word);
      if (activeTopic.current === word) {
        setData(result);
        onCacheUpdate(word, result);
      }
    } catch (e) {
      setErrorMsg("Fetch error.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleRegenerate = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!isOnline || isRegenerating) return;
    setIsRegenerating(true);
    try {
      const result = await fetchWordData(topic);
      setData(result);
      onCacheUpdate(topic, result);
    } catch (e) {
      console.error("Regeneration failed", e);
    } finally {
      setIsRegenerating(false);
    }
  };

  const handleWordClick = async (e: React.MouseEvent, word: string) => {
    e.stopPropagation();
    const x = e.clientX, y = e.clientY;
    setTooltip({ word, text: 'Loading...', x, y });
    try {
        const fullDef = await getShortDefinition(word);
        setTooltip(prev => prev?.word === word ? { ...prev, text: fullDef } : prev);
    } catch (err) {
        setTooltip(null);
    }
  };

  if (topic === "__EMPTY_FALLBACK__") {
      return (
          <div className="flashcard-container" style={{ justifyContent: 'center' }}>
              <div className="card-face card-front" style={{ height: 'auto', padding: '40px' }}>
                  <div style={{ fontSize: '3rem', marginBottom: '16px' }}>📚</div>
                  <h2 style={{ textAlign: 'center', marginBottom: '12px' }}>Library is Empty</h2>
                  <p style={{ textAlign: 'center', opacity: 0.7, marginBottom: '24px' }}>Start building your library.</p>
                  <button className="primary-btn" onClick={onOpenImport}>Import Words</button>
              </div>
          </div>
      );
  }

  const isFavorite = favoriteWords.includes(topic);
  const srsItem = srsData[topic];
  const statusLabel = isExploreMode ? `PACK ${exploreProgress?.current}/${exploreProgress?.total}` : (!srsItem || srsItem.reviewCount === 0 ? 'NEW' : (srsItem.masteryLevel >= 5 ? 'MASTERED' : 'LEARNING'));

  return (
    <div className="flashcard-container" onClick={() => setTooltip(null)}>
      <div className={`flashcard ${isFlipped ? 'flipped' : ''}`} onClick={() => !isFlipped && !errorMsg && setIsFlipped(true)}>
        <div className="card-face card-front">
           <div className="card-actions-top">
               <button className={`icon-btn fav-btn ${isFavorite ? 'faved' : ''}`} onClick={(e) => { e.stopPropagation(); onToggleFavorite(topic); }}>
                 <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill={isFavorite ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2.5"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/></svg>
               </button>
           </div>
           <div className="word-display" style={{ fontSize: '2.8rem', fontWeight: 900 }}>{topic}</div>
           <div className="pos-tag" style={{ color: 'var(--md-sys-color-primary)', fontWeight: 700 }}>{(data.pos || '...').toUpperCase()}</div>
           <div className="status-badge" style={{ marginTop: '20px', background: 'var(--md-sys-color-secondary-container)', color: 'var(--md-sys-color-on-secondary-container)', padding: '6px 16px', borderRadius: '20px', fontSize: '0.75rem', fontWeight: 800 }}>{statusLabel}</div>
           <div className="tap-hint" style={{ marginTop: 'auto', marginBottom: '24px', opacity: 0.5, fontWeight: 700 }}>{isLoading ? 'Loading...' : 'TAP TO REVEAL'}</div>
        </div>

        <div className="card-face card-back">
           <div className="card-back-header" style={{ padding: '20px 24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
             <h2 style={{ fontSize: '1.4rem', fontWeight: 800, margin: 0 }}>{topic}</h2>
             <button className={`icon-btn fav-btn ${isFavorite ? 'faved' : ''}`} onClick={(e) => { e.stopPropagation(); onToggleFavorite(topic); }}>
                <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill={isFavorite ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2.5"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/></svg>
             </button>
           </div>

           <div className="card-back-scrollable" style={{ padding: '0 24px 20px' }}>
                {visibilitySettings.definition && (
                    <div style={{ marginBottom: '16px' }}>
                        <div className="section-label" style={{ fontSize: '0.65rem', fontWeight: 800, opacity: 0.5, marginBottom: '4px' }}>DEFINITION</div>
                        <div style={{ fontSize: '1rem', lineHeight: 1.5 }}>
                            <InteractiveText text={String(data.definition || '...')} onWordClick={handleWordClick} />
                        </div>
                    </div>
                )}
                {visibilitySettings.bengali && data.bengali && (
                    <div style={{ marginBottom: '16px' }}>
                        <div className="section-label" style={{ fontSize: '0.65rem', fontWeight: 800, opacity: 0.5, marginBottom: '4px' }}>BENGALI</div>
                        <div style={{ fontSize: '1.1rem', fontWeight: 600 }}>{data.bengali}</div>
                    </div>
                )}
                {visibilitySettings.context && (
                    <div style={{ marginBottom: '16px' }}>
                        <div className="section-label" style={{ fontSize: '0.65rem', fontWeight: 800, opacity: 0.5, marginBottom: '4px' }}>CONTEXT</div>
                        <div style={{ background: 'var(--md-sys-color-surface-variant)', padding: '12px', borderRadius: '16px', fontStyle: 'italic', fontSize: '0.9rem' }}>
                            <InteractiveText text={String(data.context || '...')} onWordClick={handleWordClick} />
                        </div>
                    </div>
                )}
                {visibilitySettings.family && data.family && (
                    <div style={{ marginBottom: '16px' }}>
                        <div className="section-label" style={{ fontSize: '0.65rem', fontWeight: 800, opacity: 0.5, marginBottom: '4px' }}>FAMILY</div>
                        <div className="chip-container" style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                            {data.family.split(',').map(f => <span key={f} className="chip" style={{ fontSize: '0.75rem' }} onClick={(e) => { e.stopPropagation(); onNavigate(capitalize(f.replace(/\s*\([^)]*\)/g, '').trim()), true); }}>{f.trim()}</span>)}
                        </div>
                    </div>
                )}
           </div>

           <div className="card-back-footer" style={{ marginTop: 'auto', padding: '16px 24px', borderTop: '1px solid var(--border-color)', display: 'flex', gap: '12px' }}>
               <button 
                  className={`icon-btn regen-btn ${isRegenerating ? 'spinning' : ''}`} 
                  onClick={handleRegenerate}
                  title="AI Regenerate"
                  disabled={isRegenerating || !isOnline}
                  style={{ background: 'var(--md-sys-color-secondary-container)', borderRadius: '12px', width: '48px', height: '48px' }}
               >
                  <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="currentColor"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
               </button>
               <button className="tonal-btn" style={{ flex: 1, padding: '12px' }} onClick={(e) => { e.stopPropagation(); setIsFlipped(false); onUpdateSRS(topic, 'dont_know'); }}>STUDY AGAIN</button>
           </div>
        </div>
      </div>

      <div className="external-actions" style={{ display: 'flex', gap: '12px', padding: '0 16px', marginTop: '20px' }}>
        {!isExploreMode ? (
            <>
                <button className="tonal-btn" style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }} onClick={() => onUpdateSRS(topic, 'know')}>
                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="20 6 9 17 4 12"/></svg>
                    Mastered
                </button>
                <button className="primary-btn" style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }} onClick={() => onNavigate('__RANDOM__')}>
                    Next Word
                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="9 18 15 12 9 6"/></svg>
                </button>
            </>
        ) : (
            <>
                <button className="icon-btn" style={{ background: 'var(--md-sys-color-surface-container)' }} onClick={() => onNavigate('__PREV__')} disabled={exploreProgress?.current === 1}>
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="15 18 9 12 15 6"/></svg>
                </button>
                <button className="tonal-btn" style={{ flex: 1 }} onClick={() => onUpdateSRS(topic, 'know')}>GOT IT</button>
                <button className="primary-btn" style={{ minWidth: '100px' }} onClick={() => onNavigate(exploreProgress?.current === exploreProgress?.total ? '__GENERATE__' : '__RANDOM__')}>
                    {exploreProgress?.current === exploreProgress?.total ? 'NEW PACK' : 'NEXT'}
                </button>
            </>
        )}
      </div>

      {tooltip && <WordTooltip {...tooltip} onOpen={() => onNavigate(tooltip.word, true)} onClose={() => setTooltip(null)} />}
      <style>{`
        .regen-btn.spinning svg { animation: spin 1.2s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
      `}</style>
    </div>
  );
};

