import React, { useState, useMemo, useRef } from 'react';
import { SRSItem } from '../services/srsService';
import { CardData, capitalize, generateSemanticClusters, generateBulkCardData } from '../services/dictionaryService';
import { SemanticCluster } from '../App';
import EditWordModal from './EditWordModal';

interface SavedWordsListProps {
  savedWords: string[];
  favoriteWords: string[];
  trashedWords: string[];
  srsData: Record<string, SRSItem>;
  cardCache: Record<string, CardData>;
  onNavigate: (word: string, initialFlipped?: boolean) => void;
  onDeleteMultiple: (words: string[]) => void;
  onRestoreFromTrash: (words: string[]) => void;
  onPermanentDelete: (words: string[]) => void;
  onOpenImport: () => void;
  onUpdateWordData: (oldWord: string, newWord: string, newData: CardData) => void;
  semanticClusters: SemanticCluster[];
  setSemanticClusters: (clusters: SemanticCluster[]) => void;
  clusterSimilarity: number;
  setClusterSimilarity: (val: number) => void;
  isOnline: boolean;
}

type SortType = 'alpha' | 'time';
type SortOrder = 'asc' | 'desc';
type MasteryFilter = 'all' | 'new' | 'learning' | 'mastered';
type ViewType = 'list' | 'family' | 'synonym';

const SavedWordsList: React.FC<SavedWordsListProps> = ({ 
    savedWords, favoriteWords, trashedWords, srsData, cardCache, onNavigate, onDeleteMultiple, onRestoreFromTrash, onPermanentDelete, onOpenImport, onUpdateWordData,
    semanticClusters, setSemanticClusters, clusterSimilarity, setClusterSimilarity, isOnline
}) => {
  const [activeTab, setActiveTab] = useState<'all' | 'favorites'>('all');
  const [sortBy, setSortBy] = useState<SortType>('time');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');
  const [filter, setFilter] = useState<MasteryFilter>('all');
  const [viewType, setViewType] = useState<ViewType>('list');
  const [selectedFamilyGroup, setSelectedFamilyGroup] = useState<any>(null);
  const [selectedCluster, setSelectedCluster] = useState<SemanticCluster | null>(null);
  const [isRefreshingClusters, setIsRefreshingClusters] = useState(false);
  const [isRegeneratingBulk, setIsRegeneratingBulk] = useState(false);

  const [selectionMode, setSelectionMode] = useState(false);
  const [selectedWords, setSelectedWords] = useState<Set<string>>(new Set());
  const longPressTimer = useRef<number | null>(null);
  const [editingWord, setEditingWord] = useState<string | null>(null);

  const baseList = activeTab === 'all' ? savedWords : favoriteWords;

  const filteredAndSortedList = useMemo(() => {
    let list = [...baseList];
    if (filter !== 'all') {
        list = list.filter(word => {
            const item = srsData[word];
            const mastery = item?.masteryLevel || 0;
            const revCount = item?.reviewCount || 0;
            if (filter === 'new') return revCount === 0;
            if (filter === 'learning') return revCount > 0 && mastery < 5;
            if (filter === 'mastered') return mastery >= 5;
            return true;
        });
    }
    list.sort((a, b) => {
        if (sortBy === 'alpha') {
            const res = a.localeCompare(b);
            return sortOrder === 'asc' ? res : -res;
        } else {
            const idxA = savedWords.indexOf(a);
            const idxB = savedWords.indexOf(b);
            return sortOrder === 'asc' ? idxB - idxA : idxA - idxB;
        }
    });
    return list;
  }, [baseList, sortBy, sortOrder, filter, srsData, savedWords]);

  const handleBulkRegenerate = async () => {
    if (!isOnline || isRegeneratingBulk || selectedWords.size === 0) return;
    setIsRegeneratingBulk(true);
    try {
      // Fix: Explicitly type wordsToRegen as string[] to avoid unknown[] inference error
      const wordsToRegen = Array.from<string>(selectedWords);
      const newCards = await generateBulkCardData(wordsToRegen);
      newCards.forEach(card => {
        if (card.word) onUpdateWordData(card.word, card.word, card);
      });
      setSelectionMode(false);
      setSelectedWords(new Set());
    } catch (e) {
      alert("Bulk regeneration failed. Please check connection.");
    } finally {
      setIsRegeneratingBulk(false);
    }
  };

  const toggleSelection = (word: string) => {
    const next = new Set(selectedWords);
    if (next.has(word)) next.delete(word); else next.add(word);
    setSelectedWords(next);
    if (next.size === 0) setSelectionMode(false);
  };

  const handleItemClick = (word: string) => {
    if (selectionMode) { toggleSelection(word); } else { onNavigate(word, true); }
  };

  return (
    <div className="saved-list-view">
      {selectionMode && (
          <div className="selection-bar">
              <button className="icon-btn-selection" onClick={() => { setSelectionMode(false); setSelectedWords(new Set()); }}>
                  <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
              </button>
              <div className="selection-count">{selectedWords.size} Selected</div>
              <div className="selection-actions-group">
                <button className={`icon-btn-selection regen-circle ${isRegeneratingBulk ? 'spinning' : ''}`} onClick={handleBulkRegenerate} disabled={isRegeneratingBulk || !isOnline} title="Bulk AI Update">
                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="currentColor"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
                </button>
                <button className="icon-btn-selection trash-circle" onClick={() => { if(confirm(`Delete ${selectedWords.size} words?`)) { 
                    // Fix: Explicitly type as string[] for onDeleteMultiple to avoid unknown[] inference error
                    onDeleteMultiple(Array.from<string>(selectedWords)); 
                    setSelectionMode(false); 
                    setSelectedWords(new Set()); 
                } }}>
                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#ff3b30" strokeWidth="2.5"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                </button>
              </div>
          </div>
      )}

      <div className="list-tabs-container">
          <div className="list-tabs">
              <button onClick={() => setActiveTab('all')} className={activeTab === 'all' ? 'active' : ''}>LIBRARY</button>
              <button onClick={() => setActiveTab('favorites')} className={activeTab === 'favorites' ? 'active' : ''}>FAVORITES</button>
          </div>
      </div>

      <div className="words-scroll-list">
          {filteredAndSortedList.map(word => (
            <div 
                key={word} 
                className={`modern-word-card ${selectedWords.has(word) ? 'selected' : ''}`} 
                onClick={() => handleItemClick(word)} 
                onPointerDown={(e) => {
                    longPressTimer.current = window.setTimeout(() => {
                        setSelectionMode(true);
                        toggleSelection(word);
                    }, 600);
                }}
                onPointerUp={() => clearTimeout(longPressTimer.current)}
                onPointerMove={() => clearTimeout(longPressTimer.current)}
            >
                <div className="card-info">
                    <div className="card-top-row">
                        <span className="word-title">{word}</span>
                        <div className="card-indicators">
                            {favoriteWords.includes(word) && <span className="fav-indicator">❤️</span>}
                            <button className="edit-mini-btn" onClick={(e) => { e.stopPropagation(); setEditingWord(word); }}>
                                <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"></path><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"></path></svg>
                            </button>
                        </div>
                    </div>
                    <p className="word-snippet">{cardCache[word]?.definition || 'No definition cached...'}</p>
                </div>
            </div>
          ))}
      </div>

      {editingWord && <EditWordModal word={editingWord} initialData={cardCache[editingWord]} onClose={() => setEditingWord(null)} onSave={onUpdateWordData} />}

      <style>{`
        .regen-circle { background: white !important; color: var(--accent-primary) !important; border-radius: 50% !important; width: 40px !important; height: 40px !important; margin-right: 8px; }
        .regen-circle.spinning svg { animation: spin 1.2s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
      `}</style>
    </div>
  );
};

