import { GoogleGenAI, Type } from '@google/genai';
import { DICTIONARY_WORDS, VOCAB_LEVELS } from './dictionaryData';
import { SemanticCluster } from '../App';

export interface CardData {
  pos: string;
  ipa?: string;
  definition: string;
  bengali: string;
  family: string;
  context: string;
  synonyms: string;
  antonyms: string;
  difficulty: string;
  usage_notes?: string;
  source?: string;
  word?: string;
}

export type VocabLevel = 'basic' | 'intermediate' | 'gre' | 'ielts' | 'expert';

let aiInstance: GoogleGenAI | null = null;

const getAIClient = () => {
  if (!aiInstance) {
    aiInstance = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiInstance;
};

export const capitalize = (s: string) => s ? s.charAt(0).toUpperCase() + s.slice(1).toLowerCase() : s;

const safeJsonParse = (text: string | undefined, fallback: any) => {
  if (!text) return fallback;
  try {
    const cleanText = text.replace(/```json/g, '').replace(/```/g, '').trim();
    return JSON.parse(cleanText);
  } catch (e) {
    console.error("JSON Parse failed", e, text);
    return fallback;
  }
};

const cardSchema = {
  type: Type.OBJECT,
  properties: {
    pos: { type: Type.STRING },
    definition: { type: Type.STRING },
    bengali: { type: Type.STRING },
    family: { type: Type.STRING },
    context: { type: Type.STRING },
    synonyms: { type: Type.STRING },
    antonyms: { type: Type.STRING },
    difficulty: { type: Type.STRING },
    usage_notes: { type: Type.STRING }
  },
  required: ["pos", "definition", "bengali", "family", "context", "synonyms", "antonyms", "difficulty"]
};

export async function searchVocabulary(query: string): Promise<string[]> {
  const cleanQuery = query.trim();
  if (cleanQuery.length < 2) return [];
  if (!navigator.onLine) {
    return DICTIONARY_WORDS.filter(w => w.toLowerCase().startsWith(cleanQuery.toLowerCase())).slice(0, 8).map(capitalize);
  }
  try {
    const response = await fetch(`https://api.datamuse.com/sug?s=${encodeURIComponent(cleanQuery)}&max=8`);
    const data = await response.json();
    return data.map((item: any) => capitalize(item.word));
  } catch (error) {
    return DICTIONARY_WORDS.filter(w => w.toLowerCase().startsWith(cleanQuery.toLowerCase())).slice(0, 8).map(capitalize);
  }
}

export async function fetchWordData(word: string, definitionStyle: string = 'standard', retries = 1): Promise<CardData> {
  const normalizedWord = capitalize(word);
  if (!navigator.onLine) {
    return {
      pos: 'word',
      definition: `Details for "${normalizedWord}" are pending.`,
      bengali: 'অফলাইন থাকার কারণে বিস্তারিত পাওয়া যায়নি',
      family: 'N/A',
      context: `The word "${normalizedWord}" is in your library.`,
      synonyms: 'N/A',
      antonyms: 'N/A',
      difficulty: 'Standard',
      source: 'Local Cache',
      word: normalizedWord
    };
  }
  const ai = getAIClient();
  const prompt = `Act as a world-class lexicographer and academic linguist. Define "${normalizedWord}" for a professional vocabulary flashcard.
  Style: ${definitionStyle}.
  Rules:
  1. DEFINITION: Precise, nuanced, and academic-grade.
  2. BENGALI: Provide a sophisticated and accurate translation (Bangla Artho).
  3. USAGE NOTES: Include mnemonics or common traps using [MNEMONIC] or [TRAP] tags.
  4. FAMILY: Include related forms with POS in brackets.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { 
        responseMimeType: "application/json", 
        responseSchema: cardSchema,
        thinkingConfig: { thinkingBudget: 0 } 
      }
    });
    const data = safeJsonParse(response.text, {});
    if (data.bengali) data.bengali = data.bengali.replace(/\s*\([^)]*[a-zA-Z][^)]*\)/g, '').trim();
    return { ...data, word: normalizedWord, source: 'Gemini AI' };
  } catch (error) {
    if (retries > 0) return fetchWordData(normalizedWord, definitionStyle, retries - 1);
    throw error;
  }
}

/**
 * Enhanced Explore Strategy:
 * Uses Datamuse API to subset potential candidate words by topic/level, 
 * filters locally against the user's saved list, then asks Gemini to define the fresh subset.
 */
export async function fetchExplorePack(level: VocabLevel = 'intermediate', count: number = 10, excludeWords: string[] = []): Promise<CardData[]> {
  if (!navigator.onLine) throw new Error("Offline");

  const excludeSet = new Set(excludeWords.map(w => w.toLowerCase()));
  const topicPools = {
    basic: ['nature', 'family', 'house', 'city'],
    intermediate: ['business', 'travel', 'emotion', 'culture'],
    gre: ['philosophy', 'logic', 'art', 'rhetoric', 'politics'],
    ielts: ['academic', 'environment', 'society', 'technology'],
    expert: ['literature', 'science', 'theory', 'abstract', 'obscure']
  };

  const currentPool = topicPools[level] || topicPools.intermediate;
  const randomTopic = currentPool[Math.floor(Math.random() * currentPool.length)];

  try {
    // 1. Get a broad pool of words from Datamuse (External subsetting)
    const datamuseRes = await fetch(`https://api.datamuse.com/words?topics=${randomTopic}&max=150`);
    const datamuseData = await datamuseRes.json();

    // 2. Filter locally to guarantee words are not in the saved list
    const freshWords = datamuseData
      .map((item: any) => item.word)
      .filter((word: string) => 
        word.length > 3 && 
        !word.includes(' ') && 
        !excludeSet.has(word.toLowerCase())
      )
      .slice(0, count);

    if (freshWords.length < count / 2) {
        // Fallback to pure AI if Datamuse subsetting is too restrictive
        return await generatePureAiPack(level, count, excludeWords);
    }

    // 3. Generate high-quality data for these specific fresh words
    return await generateBulkCardData(freshWords);
  } catch (e) {
    console.warn("External word discovery failed, using fallback AI discovery", e);
    return await generatePureAiPack(level, count, excludeWords);
  }
}

async function generatePureAiPack(level: string, count: number, excludeWords: string[]): Promise<CardData[]> {
  const ai = getAIClient();
  const prompt = `Generate ${count} sophisticated ${level}-level English vocabulary words that are NOT in this list: ${excludeWords.slice(-100).join(', ')}.`;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: { 
        type: Type.ARRAY, 
        items: { 
            ...cardSchema, 
            properties: { ...cardSchema.properties, word: { type: Type.STRING } }, 
            required: [...cardSchema.required, "word"] 
        } 
      }
    }
  });
  return safeJsonParse(response.text, []);
}

export async function generateBulkCardData(words: string[]): Promise<CardData[]> {
  if (words.length === 0) return [];
  const ai = getAIClient();
  const prompt = `Act as a world-renowned dictionary editor. Create professional-grade vocabulary cards for these words: ${words.join(', ')}.
  For each word, ensure high-fidelity definitions, academic examples, and perfect Bengali translations.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: { 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          ...cardSchema,
          properties: { ...cardSchema.properties, word: { type: Type.STRING } },
          required: [...cardSchema.required, "word"]
        }
      }
    }
  });

  const results = safeJsonParse(response.text, []);
  return results.map((item: any) => ({
    ...item,
    word: capitalize(item.word),
    source: 'Gemini AI'
  }));
}

export async function generateBulkWordData(words: string[]): Promise<Record<string, CardData>> {
  const cards = await generateBulkCardData(words);
  const cache: Record<string, CardData> = {};
  cards.forEach(card => {
    if (card.word) cache[card.word] = card;
  });
  return cache;
}

export async function generateSemanticClusters(words: string[], level: number = 2): Promise<SemanticCluster[]> {
    if (!navigator.onLine || words.length === 0) return [];
    const ai = getAIClient();
    const prompt = `Group these words by deep semantic similarity (Level ${level}/2): ${words.join(', ')}.`;
    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { 
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                members: { type: Type.ARRAY, items: { type: Type.STRING } },
                explanation: { type: Type.STRING }
              },
              required: ["title", "members", "explanation"]
            }
          },
          thinkingConfig: { thinkingBudget: 0 } 
        }
    });
    const data = safeJsonParse(response.text, []);
    return data.map((item: any, idx: number) => ({
        ...item,
        id: `cluster-${idx}-${Date.now()}`,
        isAiGenerated: true
    }));
}

export async function fetchContextSentence(word: string): Promise<string> {
  const ai = getAIClient();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide one high-level academic example sentence for the word "${word}":`,
      config: { thinkingConfig: { thinkingBudget: 0 } }
    });
    return response.text?.trim() || `An illustrative context for ${word}.`;
  } catch (error) {
    return `Could not generate sentence for "${word}".`;
  }
}

export async function getShortDefinition(word: string): Promise<string> {
  try {
    const data = await fetchWordData(word);
    return `(${data.pos}) ${data.definition}\n${data.bengali}`;
  } catch (e) {
    return "Definition unavailable.";
  }
}

