                {visibilitySettings.family && familyList.length > 0 && (
                  <>
                    <div className="section-label">WORD FAMILY</div>
                    <div className="chip-container">
                        {familyList.map(f => {
                            const clean = f.replace(/\s*\([^)]*\)/g, '').trim();
                            return (
