import React, { useState, useEffect } from 'react';
import { CardData, fetchWordData, fetchContextSentence } from '../services/dictionaryService';

interface EditWordModalProps {
  word: string;
  initialData: CardData;
  onClose: () => void;
  onSave: (oldWord: string, newWord: string, newData: CardData) => void;
}

const EditWordModal: React.FC<EditWordModalProps> = ({ word, initialData, onClose, onSave }) => {
  const [formData, setFormData] = useState<CardData>({ ...initialData });
  const [tempWord, setTempWord] = useState(word);
  const [viewMode, setViewMode] = useState<'form' | 'json'>('form');
  const [jsonText, setJsonText] = useState('');
  const [jsonError, setJsonError] = useState<string | null>(null);

  const [isAiLoading, setIsAiLoading] = useState(false);
  const [isSentenceLoading, setIsSentenceLoading] = useState(false);

  // Tracks if the current state differs from the initial props
  const isDirty = tempWord !== word || JSON.stringify(formData) !== JSON.stringify(initialData);

  useEffect(() => {
    if (viewMode === 'json') {
      const fullObject = { word: tempWord, ...formData };
      setJsonText(JSON.stringify(fullObject, null, 2));
    }
  }, [viewMode, formData, tempWord]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleJsonChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setJsonText(e.target.value);
    setJsonError(null);
  };

  const validateAndSyncJson = (): boolean => {
    try {
      const parsed = JSON.parse(jsonText);
      if (!parsed.word) throw new Error("Missing 'word' field in JSON.");
      const { word: newW, ...rest } = parsed;
      setTempWord(newW);
      setFormData(rest as CardData);
      setJsonError(null);
      return true;
    } catch (e: any) {
      setJsonError(e.message);
      return false;
    }
  };

  const handleToggleMode = () => {
    if (viewMode === 'json') {
      if (validateAndSyncJson()) setViewMode('form');
    } else {
      setViewMode('json');
    }
  };

  const handleAiGlobalRefresh = async () => {
    if (!tempWord.trim() || isAiLoading) return;
    setIsAiLoading(true);
    try {
      const newData = await fetchWordData(tempWord.trim());
      setFormData(newData);
    } catch (e) {
      console.error("AI Refresh failed", e);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleAiSentenceRefresh = async () => {
    if (!tempWord.trim() || isSentenceLoading) return;
    setIsSentenceLoading(true);
    try {
      const newSentence = await fetchContextSentence(tempWord.trim());
      setFormData(prev => ({ ...prev, context: newSentence }));
    } catch (e) {
      console.error("Sentence Refresh failed", e);
    } finally {
      setIsSentenceLoading(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (viewMode === 'json') {
      if (!validateAndSyncJson()) return;
    }
    if (!tempWord.trim()) return;
    onSave(word, tempWord.trim(), formData);
  };

  return (
    <div className="auth-overlay" onClick={onClose}>
      <div className={`auth-container edit-word-container ${viewMode === 'json' ? 'json-mode-active' : ''}`} onClick={(e) => e.stopPropagation()}>
        <div className="auth-header">
          <div className="header-info-group">
            <h3 style={{ fontSize: '1.25rem', fontWeight: 800 }}>{viewMode === 'form' ? 'Edit Word' : 'Raw Editor'}</h3>
            <span className="subtitle">{tempWord}</span>
          </div>
          <div className="header-actions-group">
            {viewMode === 'form' && (
              <button className={`ai-refresh-btn ${isAiLoading ? 'loading' : ''}`} onClick={handleAiGlobalRefresh} title="AI Refresh" disabled={isAiLoading}>
                <svg className="sparkle-icon-colorful" xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
              </button>
            )}
            <button className="mode-toggle-btn" onClick={handleToggleMode}>{viewMode === 'form' ? '{ }' : '📝'}</button>
            <button onClick={onClose} className="close-button-cross"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="edit-word-form">
          {viewMode === 'form' ? (
            <div className="form-content-area">
              <div className="form-group word-primary-group"><label>The Word</label><input name="word" value={tempWord} onChange={(e) => setTempWord(e.target.value)} className="word-edit-input" /></div>
              <div className="form-group"><label>POS</label><input name="pos" value={formData.pos} onChange={handleChange} /></div>
              <div className="form-group"><label>Definition</label><textarea name="definition" value={formData.definition} onChange={handleChange} rows={2} /></div>
              <div className="form-group"><label>Bengali</label><input name="bengali" value={formData.bengali} onChange={handleChange} /></div>
              <div className="form-group">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}><label>Context</label><button type="button" className={`mini-ai-btn ${isSentenceLoading ? 'loading' : ''}`} onClick={handleAiSentenceRefresh} disabled={isSentenceLoading}><span>✨ AI</span></button></div>
                <textarea name="context" value={formData.context} onChange={handleChange} rows={2} />
              </div>
              <div className="form-grid">
                <div className="form-group"><label>Synonyms</label><input name="synonyms" value={formData.synonyms} onChange={handleChange} /></div>
                <div className="form-group"><label>Antonyms</label><input name="antonyms" value={formData.antonyms} onChange={handleChange} /></div>
              </div>
            </div>
          ) : (
            <div className="json-editor-area"><textarea className={`json-textarea ${jsonError ? 'error' : ''}`} value={jsonText} onChange={handleJsonChange} spellCheck={false} />{jsonError && <div className="json-error-msg">⚠️ Invalid JSON</div>}</div>
          )}

          <div className="form-actions">
            <button type="button" className="auth-btn" onClick={onClose} style={{ background: 'var(--accent-secondary)' }}>Cancel</button>
            <button type="submit" className="auth-btn primary" disabled={!isDirty || !!jsonError || isAiLoading}>Save</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditWordModal;

/**
