          }
          .regen-btn-footer {
              background: var(--accent-secondary);
              color: var(--accent-primary);
              border: 1px solid var(--border-color);
              border-radius: 8px;
              width: 32px;
              height: 32px;
              display: flex;
              align-items: center;
              justify-content: center;
              transition: transform 0.2s;
          }
          .regen-btn-footer:active { transform: scale(0.9); }
          .regen-btn-footer.spinning svg { animation: spin 1s linear infinite; }
          @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }

          .action-btn-back {
              padding: 8px 14px;
              border-radius: 10px;
              font-weight: 700;
              font-size: 0.75rem;
              background: var(--accent-secondary);
              color: var(--accent-primary);
              border: 1px solid var(--border-color);
          }
          .action-btn-back:active { transform: scale(0.95); }

          .nav-icon-btn {
            width: 56px;
            height: 56px;
            border-radius: 50%;
            background: var(--card-bg);
            border: 1px solid var(--border-color);
            color: var(--text-primary);
            display: flex;
            align-items: center;
            justify-content: center;
            box-shadow: var(--shadow-sm);
            transition: all 0.2s;
            flex-shrink: 0;
          }
          .nav-icon-btn:disabled { opacity: 0.3; cursor: not-allowed; }
          .nav-icon-btn:active:not(:disabled) { transform: scale(0.9); background: var(--accent-secondary); }

          .sparkle-icon-filled {
              color: #FFD700;
              filter: drop-shadow(0 0 4px rgba(255, 215, 0, 0.5));
          }

          .nav-icon-btn.primary-gen { 
            background: var(--accent-primary); 
            color: white; 
            border-color: var(--accent-primary);
            animation: pulse-gen 2s infinite;
          }
          @keyframes pulse-gen {
              0% { box-shadow: 0 0 0 0 rgba(88, 86, 214, 0.4); }
              70% { box-shadow: 0 0 0 10px rgba(88, 86, 214, 0); }
              100% { box-shadow: 0 0 0 0 rgba(88, 86, 214, 0); }
          }

          .status-badge.explore-badge {
            background: linear-gradient(135deg, #5856d6 0%, #ff2d55 100%);
            color: white;
            border: none;
          }

          .usage-box-container {
              display: flex;
              flex-direction: column;
              gap: 8px;
