    synonyms: 'N/A',
    antonyms: 'N/A',
    difficulty: 'Standard',
    source: 'Local Cache',
    word: normalizedWord
  };

  if (!navigator.onLine) return localFallback;
  const ai = getAIClient();
  const styleInstruction = definitionStyle === 'concise' 
    ? 'Keep the definition brief (under 12 words).' 
    : (definitionStyle === 'detailed' ? 'Provide a detailed, nuanced definition.' : 'Provide a standard, clear definition.');

  const prompt = `Act as a world-class lexicographer. Define the English word "${normalizedWord}" for a professional vocabulary card. 
  ${styleInstruction} 
  Rules: 
  - DEFINITION: Academic grade.
  - BENGALI: Accurate translation.
  - FAMILY: Include related forms with POS in brackets (e.g. "happiness (n)"). 
  - USAGE NOTES: Include mnemonics or tips using [TRAP], [MNEMONIC], [VIBE], [TIP].`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { 
        responseMimeType: "application/json", 
        responseSchema: cardSchema,
