/**
 * Robust Explore Strategy:
 * 1. Find a broad pool of words using Datamuse (based on thematic topics for each level).
 * 2. Filter this pool locally against the user's saved words.
 * 3. Use Gemini to generate high-quality card data for the guaranteed fresh subset.
 */
export async function fetchExplorePack(level: VocabLevel = 'intermediate', count: number = 10, excludeWords: string[] = []): Promise<CardData[]> {
  if (!navigator.onLine) throw new Error("Offline");

  const topicPools: Record<VocabLevel, string[]> = {
    basic: ['nature', 'family', 'house', 'city', 'emotion'],
    intermediate: ['business', 'travel', 'culture', 'science', 'society'],
    gre: ['philosophy', 'logic', 'art', 'rhetoric', 'politics', 'literature'],
    ielts: ['academic', 'environment', 'technology', 'education', 'economics'],
    expert: ['theoretical', 'abstract', 'obscure', 'linguistics', 'specialized']
  };

  const excludeSet = new Set(excludeWords.map(w => w.toLowerCase()));
  const currentPool = topicPools[level] || topicPools.intermediate;
  const randomTopic = currentPool[Math.floor(Math.random() * currentPool.length)];

  try {
    // 1. Get a word pool from Datamuse (Topic-based subsetting)
    const datamuseRes = await fetch(`https://api.datamuse.com/words?topics=${randomTopic}&max=150`);
    const datamuseData = await datamuseRes.json();

    // 2. Filter locally to find words NOT in current library
    const freshWords = datamuseData
      .map((item: any) => item.word)
      .filter((word: string) => 
        word.length > 3 && 
        !word.includes(' ') && 
        !excludeSet.has(word.toLowerCase())
      )
      .slice(0, count);

    // 3. If we didn't find enough words, fall back to pure AI generation
    if (freshWords.length < count / 2) {
        return await generateFallbackExplorePack(level, count, excludeWords);
    }

    // 4. Generate high-quality data for the selected unique words
    return await generateBulkCardData(freshWords);
  } catch (e) {
    console.warn("Datamuse discovery failed, using fallback AI discovery", e);
    return await generateFallbackExplorePack(level, count, excludeWords);
  }
}

async function generateFallbackExplorePack(level: string, count: number, excludeWords: string[]): Promise<CardData[]> {
  const ai = getAIClient();
  const excludeStr = excludeWords.length > 0 ? `Do NOT include: ${excludeWords.slice(-100).join(', ')}.` : '';
  const prompt = `Generate ${count} sophisticated ${level}-level English vocabulary words. ${excludeStr}`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { 
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
              ...cardSchema,
              properties: { ...cardSchema.properties, word: { type: Type.STRING } },
              required: [...cardSchema.required, "word"]
          }
        },
        thinkingConfig: { thinkingBudget: 0 } 
      }
    });
    const data = safeJsonParse(response.text, []);
    return data.map((item: any) => ({ 
      ...item, 
      word: capitalize(item.word || ''), 
      bengali: item.bengali?.replace(/\s*\([^)]*\)/g, '').trim(), 
      source: 'Gemini AI' 
    }));
  } catch (error) {
    return [];
  }
}

