  border-radius: 12px;
  text-align: center;
  color: var(--accent-primary);
}

.stat-val { font-size: 1.1rem; font-weight: 800; }
.stat-label { font-size: 0.6rem; font-weight: 700; text-transform: uppercase; opacity: 0.8; }

.auth-overlay {
  position: fixed; top: 0; left: 0; width: 100%; height: 100%;
  background: rgba(0,0,0,0.6);
  z-index: 3000;
  display: flex; align-items: center; justify-content: center;
  padding: 2rem;
  backdrop-filter: blur(8px);
}

.auth-container {
  background: var(--card-bg);
  width: 100%; max-width: 400px;
  border-radius: 24px;
  padding: 2rem;
  box-shadow: var(--shadow-float);
  border: 1px solid var(--border-color);
  position: relative;
}

.auth-header {
  display: flex; justify-content: space-between; align-items: center;
  margin-bottom: 1.5rem;
}

.auth-input {
  width: 100%;
  padding: 12px;
  margin-bottom: 12px;
  border: 1px solid var(--border-color);
  border-radius: 12px;
  background: var(--bg-color);
  color: var(--text-primary);
  font-size: 1rem;
}

.auth-btn {
  width: 100%;
  padding: 14px;
  border-radius: 12px;
  font-weight: 600;
  font-size: 1rem;
  transition: all 0.2s;
}
.auth-btn.primary { background: var(--text-primary); color: var(--bg-color); }

/* --- CLOSE BUTTON CROSS --- */
.close-x-btn {
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--accent-primary);
  background: var(--accent-secondary);
  border: none;
  border-radius: 12px;
  transition: all 0.2s;
  cursor: pointer;
}

.close-x-btn:hover {
  background: var(--border-color);
}

/* --- REFINED BOTTOM NAV --- */

.bottom-nav-container {
  position: fixed;
  bottom: 1.5rem; /* Reduced from 2rem */
  left: 50%;
  transform: translateX(-50%);
  z-index: 100;
  width: 92%;
  max-width: 360px;
}

.bottom-nav {
  position: relative;
  background: rgba(255, 255, 255, 0.7);
  backdrop-filter: blur(24px) saturate(180%);
  -webkit-backdrop-filter: blur(24px) saturate(180%);
  padding: 6px;
  border-radius: 28px;
  display: flex;
  justify-content: space-between;
  box-shadow: 0 16px 40px rgba(0,0,0,0.08);
  border: 1px solid rgba(255,255,255,0.4);
}

[data-theme='dark'] .bottom-nav {
    background: rgba(24, 24, 27, 0.75);
    border-color: rgba(255,255,255,0.06);
    box-shadow: 0 16px 40px rgba(0,0,0,0.4);
}

/* SLIDING INDICATOR */
.nav-indicator {
  position: absolute;
  top: 6px;
  left: 6px;
  height: calc(100% - 12px);
  width: calc(33.333% - 8px);
  background: var(--accent-primary);
  border-radius: 22px;
  transition: transform 0.45s cubic-bezier(0.2, 0.8, 0.2, 1);
  z-index: 0;
  pointer-events: none;
}

.pos-home { transform: translateX(0); }
.pos-saved { transform: translateX(100%); }
.pos-profile { transform: translateX(200%); }

.nav-item {
  flex: 1;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 10px;
  border-radius: 22px;
  color: var(--text-secondary);
  transition: all 0.3s cubic-bezier(0.2, 0.8, 0.2, 1);
  z-index: 1;
}

.nav-item.active {
  color: #ffffff;
}

.nav-item:active {
  transform: scale(0.9);
}

.nav-item svg {
  width: 22px;
  height: 22px;
  transition: transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1);
}

.nav-item.active svg {
  transform: translateY(-1px);
}

.nav-item span {
  font-size: 0.8rem;
  font-weight: 700;
  opacity: 0;
  max-width: 0;
  overflow: hidden;
  transition: all 0.3s cubic-bezier(0.2, 0.8, 0.2, 1);
  white-space: nowrap;
}

.nav-item.active span {
  opacity: 1;
  max-width: 100px;
  transform: translateY(0);
}

/* --- END NAV --- */

.word-small { font-size: 1.5rem; font-weight: 800; margin: 0; }

.section-label { 
  font-size: 0.7rem; 
  font-weight: 800; 
  color: var(--accent-primary); 
  margin: 1.25rem 0 0.4rem 0; /* Reduced from 1.5rem 0 0.5rem 0 */
  letter-spacing: 1.2px; 
  text-transform: uppercase;
  opacity: 0.8;
}

.def-text { 
  font-size: 1.15rem; 
  line-height: 1.6; 
  font-weight: 500; 
  color: var(--text-primary);
}

.context-box { 
  background: var(--accent-secondary); 
  padding: 1rem 1.15rem; /* Reduced from 1.1rem 1.2rem */
  border-radius: 16px; 
  border-left: 4px solid var(--accent-primary); 
  font-style: italic; 
  margin-top: 0.5rem; 
  font-size: 1rem; 
  line-height: 1.5;
  color: var(--text-primary);
}

.etymology-text {
  font-size: 0.95rem;
  color: var(--text-secondary);
  line-height: 1.6;
}

.usage-box {
  font-size: 0.9rem; 
  background: rgba(255, 193, 7, 0.08); 
  color: #92400e; 
  padding: 0.85rem; /* Reduced from 1rem */
  border-radius: 16px; 
  border: 1px solid rgba(255, 193, 7, 0.2);
  line-height: 1.5;
}

[data-theme='dark'] .usage-box {
  background: rgba(255, 193, 7, 0.05);
  color: #fbbf24;
  border-color: rgba(251, 191, 36, 0.1);
}

.chip-container { display: flex; flex-wrap: wrap; gap: 8px; margin-top: 0.4rem; }
.chip { 
  background: var(--bg-color); 
  padding: 8px 14px; 
  border-radius: 10px; 
  font-size: 0.9rem; 
  color: var(--text-primary); 
  border: 1px solid var(--border-color);
  font-weight: 600;
  transition: all 0.2s;
}
