  flex-direction: column;
  overflow: hidden;
  position: relative;
  width: 100%;
}

.flashcard-container {
  display: flex;
  flex-direction: column;
  height: 100%;
  padding: 0.85rem;
  padding-bottom: 100px;
}

.flashcard {
  flex: 1;
  width: 100%;
  min-height: 0;
  position: relative;
  transform-style: preserve-3d;
  transition: transform 0.7s cubic-bezier(0.2, 0.8, 0.2, 1);
  cursor: pointer;
  border-radius: 32px;
  margin-bottom: 0.85rem;
}

.flashcard.flipped {
  transform: rotateY(180deg);
}

.card-face {
  position: absolute;
  width: 100%;
  height: 100%;
  backface-visibility: hidden;
  border-radius: 32px;
  background: var(--card-bg);
  box-shadow: var(--shadow-card);
  border: 1px solid var(--border-color);
  overflow: hidden;
}

.card-front {
    background: linear-gradient(145deg, var(--card-bg) 40%, #fcf9f2 100%);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 2rem;
}

[data-theme='dark'] .card-front {
    background: linear-gradient(145deg, var(--card-bg) 40%, #460914 100%);
}

.card-front .word-display {
  font-size: 2.5rem;
  font-weight: 800;
  text-align: center;
  margin-bottom: 0.5rem;
  letter-spacing: -1px;
  color: var(--text-primary);
  max-width: 100%;
  word-wrap: break-word;
}

.pos-tag {
  color: var(--accent-primary);
  font-weight: 700;
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 2px;
  margin-bottom: 1.5rem;
}

.status-badge {
  background: var(--accent-secondary);
  color: var(--text-primary);
  padding: 8px 18px;
  border-radius: 30px;
  font-size: 0.75rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  box-shadow: var(--shadow-sm);
}

.tap-hint {
  position: absolute;
  bottom: 2rem;
  color: var(--text-muted);
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  animation: pulse 2s infinite ease-in-out;
}

@keyframes pulse {
  0% { opacity: 0.6; transform: scale(1); }
  50% { opacity: 1; transform: scale(1.05); }
  100% { opacity: 0.6; transform: scale(1); }
}

.card-back {
  transform: rotateY(180deg);
  background: var(--card-bg);
  display: flex;
  flex-direction: column;
}

.card-back-header {
  flex: 0 0 auto;
  padding: 1.25rem 1.5rem;
  border-bottom: 1px solid var(--border-color);
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.card-back-scrollable {
  flex: 1;
  overflow-y: auto;
  padding: 0 1.5rem 1.5rem 1.5rem;
  -webkit-overflow-scrolling: touch;
}

.card-back-footer {
  flex: 0 0 auto;
  padding: 0.85rem 1.5rem;
  border-top: 1px solid var(--border-color);
  background: var(--card-bg);
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.external-actions {
  flex: 0 0 auto;
  display: flex;
  gap: 1rem;
  width: 100%;
}

.skip-action-btn {
  flex: 1;
  background: var(--card-bg);
  border: 1.5px solid var(--accent-secondary);
  color: var(--text-primary);
  padding: 12px 10px;
  border-radius: 50px;
  font-weight: 700;
  font-size: 0.95rem;
  box-shadow: var(--shadow-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  transition: all 0.2s ease;
}
.skip-action-btn:active { transform: scale(0.98); }

.know-btn {
    border-color: var(--accent-primary);
    color: var(--accent-primary);
    background: rgba(117, 22, 45, 0.05);
}
[data-theme='dark'] .know-btn {
    background: rgba(242, 230, 198, 0.05);
    border-color: var(--accent-primary);
    color: var(--text-primary);
}

.action-btn {
  flex: 0 0 auto; 
  padding: 10px 18px; border-radius: 12px; font-weight: 700;
  font-size: 0.85rem; display: flex; align-items: center; justify-content: center; gap: 8px;
  background: var(--accent-secondary);
  color: var(--text-primary);
}

.word-card-row {
  background: var(--card-bg);
  border-radius: 16px;
  padding: 1rem;
  margin-bottom: 0.8rem;
  display: flex;
  justify-content: space-between;
  align-items: center;
  box-shadow: var(--shadow-sm);
  cursor: pointer;
  border: 1px solid var(--border-color);
  transition: transform 0.1s;
}

.search-page-input {
  width: 100%;
  padding: 16px 16px 16px 48px; 
  border-radius: 20px;
  border: 1.5px solid var(--accent-secondary);
  background: var(--card-bg);
  color: var(--text-primary);
  font-size: 1.1rem;
  box-shadow: var(--shadow-sm);
  outline: none;
  transition: all 0.2s ease;
  -webkit-appearance: none;
}

.search-page-input:focus {
  border-color: var(--accent-primary);
  box-shadow: 0 0 0 4px rgba(117, 22, 45, 0.1);
}

.bottom-nav-container {
  position: fixed;
  bottom: 1.5rem;
  left: 50%;
  transform: translateX(-50%);
  z-index: 100;
  width: 92%;
  max-width: 360px;
}

.bottom-nav {
  position: relative;
  background: rgba(255, 255, 255, 0.8);
  backdrop-filter: blur(24px) saturate(180%);
  -webkit-backdrop-filter: blur(24px) saturate(180%);
  padding: 6px;
  border-radius: 28px;
  display: flex;
  justify-content: space-between;
  box-shadow: 0 16px 40px rgba(59, 1, 11, 0.12);
  border: 1px solid rgba(255,255,255,0.4);
}

[data-theme='dark'] .bottom-nav {
    background: rgba(59, 1, 11, 0.85);
    border-color: rgba(242, 230, 198, 0.1);
    box-shadow: 0 16px 40px rgba(0,0,0,0.4);
}

.nav-indicator {
  position: absolute;
  top: 6px;
  left: 6px;
  height: calc(100% - 12px);
  width: calc(33.333% - 8px);
  background: var(--accent-primary);
  border-radius: 22px;
  transition: transform 0.45s cubic-bezier(0.2, 0.8, 0.2, 1);
  z-index: 0;
  pointer-events: none;
}

.nav-item {
  flex: 1;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 10px;
  border-radius: 22px;
  color: var(--text-secondary);
  transition: all 0.3s cubic-bezier(0.2, 0.8, 0.2, 1);
  z-index: 1;
}

.nav-item.active {
  color: var(--bg-color);
}

.section-label { 
  font-size: 0.7rem; 
  font-weight: 800; 
  color: var(--accent-primary); 
  margin: 1.25rem 0 0.4rem 0;
  letter-spacing: 1.2px; 
  text-transform: uppercase;
}

.context-box { 
  background: var(--accent-secondary); 
  padding: 1rem 1.15rem;
  border-radius: 16px; 
  border-left: 4px solid var(--accent-primary); 
  font-style: italic; 
  margin-top: 0.5rem; 
  font-size: 1rem; 
  line-height: 1.5;
  color: var(--text-primary);
}

.usage-box {
  font-size: 0.9rem; 
  background: rgba(242, 217, 160, 0.15); 
  color: var(--text-primary); 
  padding: 0.85rem;
  border-radius: 16px; 
  border: 1px solid var(--accent-secondary);
  line-height: 1.5;
}

.chip { 
  background: var(--accent-secondary); 
  padding: 8px 14px; 
  border-radius: 10px; 
  font-size: 0.9rem; 
  color: var(--text-primary); 
  border: 1px solid transparent;
  font-weight: 700;
  transition: all 0.2s;
}
.chip:hover {
  background: var(--bg-color);
  border-color: var(--accent-primary);
}

.auth-btn.primary { background: var(--accent-primary); color: var(--bg-color); }

